settings.custom_liquid:
{%- assign loc = request.locale.iso_code | downcase -%}
<div class="lc-how" style="background:#FAFAF8">
  <div class="page-width" style="padding:56px 0;text-align:center">
    <h2 style="font-size:clamp(2rem,3.5vw,3rem);margin:0 0 2.8rem">{% if loc == 'en' %}How it works{% else %}Comment ça marche{% endif %}</h2>
    <div class="lc-how-steps">
      <div class="lc-how-step">
        <div class="lc-how-num">1</div>
        <div class="lc-how-ico">🛋️</div>
        <h3 class="lc-how-t">{% if loc == 'en' %}Choose your furniture{% else %}Choisissez vos meubles{% endif %}</h3>
        <p class="lc-how-d">{% if loc == 'en' %}Browse our catalog of 490+ products{% else %}Parcourez notre catalogue de 490+ produits{% endif %}</p>
      </div>
      <div class="lc-how-step">
        <div class="lc-how-num">2</div>
        <div class="lc-how-ico">📦</div>
        <h3 class="lc-how-t">{% if loc == 'en' %}Home delivery{% else %}Livraison à domicile{% endif %}</h3>
        <p class="lc-how-d">{% if loc == 'en' %}We deliver across Canada, free of charge{% else %}On livre partout au Canada, sans frais{% endif %}</p>
      </div>
      <div class="lc-how-step">
        <div class="lc-how-num">3</div>
        <div class="lc-how-ico">✨</div>
        <h3 class="lc-how-t">{% if loc == 'en' %}Enjoy{% else %}Profitez{% endif %}</h3>
        <p class="lc-how-d">{% if loc == 'en' %}Simple assembly, and you're all set!{% else %}Montage simple, et c'est prêt !{% endif %}</p>
      </div>
    </div>
  </div>
</div>
<style>
.lc-how-steps{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;position:relative;max-width:860px;margin:0 auto}
.lc-how-steps::before{content:'';position:absolute;top:23px;left:16.66%;width:66.66%;border-top:2px dashed #C17F3E;z-index:0}
.lc-how-step{position:relative;z-index:1;text-align:center}
.lc-how-num{width:48px;height:48px;border-radius:50%;background:#C17F3E;color:#fff;font-weight:700;font-size:1.2rem;display:flex;align-items:center;justify-content:center;margin:0 auto;position:relative;z-index:1}
.lc-how-ico{font-size:2.2rem;margin:.7rem 0 .3rem;line-height:1}
.lc-how-t{margin:.2rem 0 .4rem;font-size:1.6rem}
.lc-how-d{color:#797068;margin:0;font-size:1.4rem}
@media(max-width:749px){
.lc-how-steps{grid-template-columns:1fr;gap:0;max-width:430px;text-align:left}
.lc-how-steps::before{display:none}
.lc-how-step{display:grid;grid-template-columns:48px 1fr;column-gap:16px;text-align:left;padding-bottom:30px}
.lc-how-num{grid-column:1;grid-row:1}
.lc-how-ico{grid-column:2;grid-row:1;font-size:1.8rem;margin:0;align-self:center}
.lc-how-t{grid-column:2;grid-row:2;margin:.1rem 0 .2rem}
.lc-how-d{grid-column:2;grid-row:3;margin:0}
.lc-how-step:not(:last-child)::before{content:'';position:absolute;left:23px;top:48px;bottom:0;border-left:2px dashed #C17F3E;z-index:0}
}
</style>

{%- assign loc = request.locale.iso_code | downcase -%}
{%- if loc == 'en' -%}
  {%- assign blog_handle = 'blog' -%}{%- assign blog_title = 'Tips & inspiration' -%}{%- assign blog_cta = 'View all articles' -%}
{%- else -%}
  {%- assign blog_handle = 'actualites' -%}{%- assign blog_title = 'Conseils et inspirations' -%}{%- assign blog_cta = 'Voir tous les articles' -%}
{%- endif -%}
{%- assign lc_b = blogs[blog_handle] -%}
<div style="background:#FAFAF8">
  <div class="page-width lc-blog-wrap" style="padding:56px 0;text-align:center">
    <h2 style="font-size:clamp(2rem,3.5vw,3rem);margin:0 0 2rem">{{ blog_title }}</h2>
    <div class="lc-blog-grid" style="display:grid;grid-template-columns:repeat(3,1fr);gap:24px;text-align:left">
      {%- for article in lc_b.articles limit: 3 -%}
        <a href="{{ article.url }}" class="lc-blog-card" style="text-decoration:none;color:#1A1A2E;display:block">
          {%- if article.image -%}
            <div style="border-radius:8px;overflow:hidden;margin-bottom:.7rem"><img src="{{ article.image | image_url: width: 600 }}" alt="{{ article.title | escape }}" loading="lazy" style="width:100%;aspect-ratio:16/9;object-fit:cover;display:block"></div>
          {%- else -%}
            <div style="aspect-ratio:16/9;background:#E8E0D8;border-radius:8px;margin-bottom:.7rem"></div>
          {%- endif -%}
          <div style="font-size:1.2rem;color:#797068">{{ article.published_at | date: format: 'abbreviated_date' }}</div>
          <h3 style="font-size:1.6rem;margin:.3rem 0 0;line-height:1.3">{{ article.title | escape }}</h3>
        </a>
      {%- else -%}
        <p style="grid-column:1/-1;color:#797068">{{ blog_title }}</p>
      {%- endfor -%}
    </div>
    <div style="margin-top:1.8rem"><a href="/blogs/{{ blog_handle }}" class="lc-btn" style="display:inline-block;background:#C17F3E;color:#fff;padding:12px 24px;border-radius:6px;font-weight:700;text-decoration:none">{{ blog_cta }}</a></div>
  </div>
</div>
<style>.lc-blog-card:hover h3{text-decoration:underline}@media(max-width:749px){.lc-blog-wrap{padding:36px 0!important}.lc-blog-grid{display:flex!important;grid-template-columns:none!important;overflow-x:auto;scroll-snap-type:x mandatory;-webkit-overflow-scrolling:touch;scrollbar-width:none;gap:14px;padding-bottom:6px}.lc-blog-grid::-webkit-scrollbar{display:none}.lc-blog-card{flex:0 0 85vw;scroll-snap-align:start}}</style>

{%- assign loc = request.locale.iso_code | downcase -%}
<div id="lc-pop" class="lc-pop" role="dialog" aria-modal="true" aria-hidden="true" aria-label="{% if loc == 'en' %}First order discount{% else %}Rabais premiere commande{% endif %}">
  <div class="lc-pop__ov" data-pop-close></div>
  <div class="lc-pop__card">
    <button class="lc-pop__x" type="button" data-pop-close aria-label="{% if loc == 'en' %}Close{% else %}Fermer{% endif %}">&times;</button>
    <div class="lc-pop__inner">
      <span class="lc-pop__badge">10%</span>
      <h2 class="lc-pop__title">{% if loc == 'en' %}Get 10% off your first order{% else %}Obtenez 10% sur votre premiere commande{% endif %}</h2>
      <p class="lc-pop__sub">{% if loc == 'en' %}Sign up and receive your code by email.{% else %}Inscrivez-vous et recevez votre code par courriel.{% endif %}</p>
      <form class="lc-pop__form" method="post" action="/contact" accept-charset="UTF-8" novalidate>
        <input type="hidden" name="form_type" value="customer">
        <input type="hidden" name="utf8" value="✓">
        <input type="hidden" name="contact[tags]" value="newsletter, popup-10off">
        <input class="lc-pop__email" type="email" name="contact[email]" required autocomplete="email" placeholder="{% if loc == 'en' %}your@email.com{% else %}votre@courriel.com{% endif %}">
        <button class="lc-pop__btn" type="submit">{% if loc == 'en' %}Get my discount{% else %}Je veux mon rabais{% endif %}</button>
        <p class="lc-pop__msg" role="alert" hidden></p>
      </form>
      <div class="lc-pop__ok" hidden><p>{% if loc == 'en' %}Check your email for your 10% code!{% else %}Verifiez votre courriel pour votre code 10%!{% endif %}</p></div>
    </div>
  </div>
</div>
<style>
.lc-pop{position:fixed;inset:0;z-index:99999;display:none;align-items:center;justify-content:center;padding:16px;font-family:'DM Sans',sans-serif}
.lc-pop.is-open{display:flex}
.lc-pop__ov{position:absolute;inset:0;background:rgba(26,26,46,.55)}
.lc-pop__card{position:relative;background:#fff;border-radius:14px;max-width:420px;width:100%;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.3);animation:lc-pop-in .3s ease both}
@keyframes lc-pop-in{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:none}}
.lc-pop__x{position:absolute;top:6px;right:12px;background:none;border:0;font-size:30px;line-height:1;color:#fff;cursor:pointer;z-index:2;opacity:.85}
.lc-pop__x:hover{opacity:1}
.lc-pop__inner::before{content:'';display:block;height:88px;background:#1B2A4A}
.lc-pop__badge{position:absolute;top:54px;left:50%;transform:translateX(-50%);width:68px;height:68px;border-radius:50%;background:#D4A853;color:#1B2A4A;font-weight:700;font-size:1.9rem;display:flex;align-items:center;justify-content:center;border:4px solid #fff}
.lc-pop__title{margin:46px 24px 6px;text-align:center;font-size:1.9rem;font-weight:700;color:#1B2A4A;line-height:1.2}
.lc-pop__sub{margin:0 24px 18px;text-align:center;font-size:1.4rem;color:#5b6172}
.lc-pop__form{margin:0 24px 24px;display:flex;flex-direction:column;gap:10px}
.lc-pop__email{padding:12px 14px;border:1px solid #d9d2c7;border-radius:8px;font-size:1.5rem;font-family:inherit}
.lc-pop__email:focus{outline:2px solid #C17F3E;outline-offset:0;border-color:#C17F3E}
.lc-pop__btn{padding:13px;background:#1B2A4A;color:#fff;border:0;border-radius:8px;font-weight:700;font-size:1.5rem;cursor:pointer;font-family:inherit}
.lc-pop__btn:hover{background:#C17F3E}
.lc-pop__btn:disabled{opacity:.7;cursor:default}
.lc-pop__msg{margin:0;font-size:1.3rem;color:#c0392b;text-align:center}
.lc-pop__ok{padding:0 24px 26px;text-align:center;font-size:1.5rem;color:#1B2A4A;font-weight:600}
@media(max-width:749px){.lc-pop__card{max-width:none}.lc-pop__title{font-size:1.7rem}}
</style>
<script>
(function(){
  var KEY='lc_pop_seen_v1';
  try{ if(localStorage.getItem(KEY)) return; }catch(e){}
  var pop=document.getElementById('lc-pop'); if(!pop) return;
  var shown=false, timer;
  function show(){ if(shown) return; shown=true; pop.classList.add('is-open'); pop.setAttribute('aria-hidden','false'); try{localStorage.setItem(KEY,'1');}catch(e){} clearTimeout(timer); window.removeEventListener('scroll',onScroll); }
  function close(){ pop.classList.remove('is-open'); pop.setAttribute('aria-hidden','true'); }
  function onScroll(){ var sc=window.scrollY||document.documentElement.scrollTop; var h=document.documentElement.scrollHeight-window.innerHeight; if(h>0 && sc/h>=0.5) show(); }
  timer=setTimeout(show,5000);
  window.addEventListener('scroll',onScroll,{passive:true});
  pop.addEventListener('click',function(e){ if(e.target.closest('[data-pop-close]')) close(); });
  document.addEventListener('keydown',function(e){ if(e.key==='Escape') close(); });
  var form=pop.querySelector('.lc-pop__form');
  if(form) form.addEventListener('submit',function(e){
    e.preventDefault();
    var email=form.querySelector('.lc-pop__email'); var msg=form.querySelector('.lc-pop__msg');
    var re=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if(!re.test((email.value||'').trim())){ msg.hidden=false; msg.textContent="{% if loc == 'en' %}Please enter a valid email.{% else %}Entrez un courriel valide.{% endif %}"; return; }
    var btn=form.querySelector('.lc-pop__btn'); btn.disabled=true;
    fetch(form.action,{method:'POST',body:new FormData(form),headers:{'Accept':'text/html'}})
      .then(function(){ done(); }).catch(function(){ done(); });
    function done(){ form.hidden=true; pop.querySelector('.lc-pop__ok').hidden=false; }
  });
})();
</script>
